sql:
SELECT item_id, MAX(response_value) AS max_response_value
FROM item_responses
GROUP BY item_id;

external_knowledge:
- 'top performers' refers to participants with an average response value > 3; 
- 'higher level of understanding' refers to an average response value > 3; 
- 'specific learning group' refers to groups with condition_id = 1; 
- 'particular test' refers to responses with set_id = 1.

sql:
SELECT set_type_description
FROM sets
WHERE set_id = 1;

SELECT COUNT(response_value) AS total_zero_responses
FROM item_responses
WHERE response_value = 0;
